+        -H 'Content-Type: application/json' \
+        -H "Authorization: Bearer ${READ_TOKEN}" \
+        -d '{"data":{"x":3}}')
+    CODE=$(echo "$BODY" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('error',{}).get('code',''))" 2>/dev/null || echo "")
