    <select
      value={getSelectedDatabase()?.name ?? ''}
      onchange={(e) => {
        const name = (e.target as HTMLSelectElement).value;
        const db = databases.find(d => d.name === name) ?? null;
        setSelectedDatabase(db);
      }}
